```class Solution {
public:
    int alternateDigitSum(int n) {
        int sum = 0;
        while (n != 0) {
            int digit = n % 10;
            sum += digit * (digit < 0 ? -1 : 1);
            n /= 10;
        }
        return sum;
    }
};```

